using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Primitives;

namespace WebhookProxy
{
    [ApiController]
    [Route("[controller]")]
    public class ProxyController : ControllerBase
    {
        [HttpPost("{url}")]
        public async Task<IActionResult> Forward([FromRoute] string url, [FromBody] Stream bodyStream)
        {
            var httpClient = new HttpClient();
            using (var request = new HttpRequestMessage(HttpMethod.Post, url))
            {
                if (bodyStream != null)
                {
                    await bodyStream.CopyToAsync(await request.Content.ReadAsStreamAsync());
                }

                var response = await httpClient.SendAsync(request);
                response.EnsureSuccessStatusCode();

                return new FileStreamResult(await response.Content.ReadAsStreamAsync(), response.Content.Headers.ContentType.ToString())
                {
                    FileDownloadName = $"{Guid.NewGuid()}.{Path.GetExtension(url)}"
                };
            }
        }
    }
}